package tools

import (
	"context"
	"fmt"
	"time"

	iafv1alpha1 "github.com/dlapiduz/iaf/api/v1alpha1"
	"github.com/dlapiduz/iaf/internal/auth"
	iafgithub "github.com/dlapiduz/iaf/internal/github"
	"github.com/dlapiduz/iaf/internal/orgstandards"
	"github.com/dlapiduz/iaf/internal/sourcestore"
	"sigs.k8s.io/controller-runtime/pkg/client"
)

// Dependencies holds shared dependencies for MCP tools.
type Dependencies struct {
	Client       client.Client
	Store        *sourcestore.Store
	BaseDomain   string
	Sessions     *auth.SessionStore
	OrgStandards *orgstandards.Loader
	// GitHub fields — all three must be set for GitHub tools to be registered.
	GitHub      iafgithub.Client
	GitHubToken string // stored but never surfaced in output or logs
	GitHubOrg   string
	// Observability standards — optional override file paths.
	// When empty the embedded defaults in config/org-standards/*.json are used.
	LoggingStandardsFile string
	MetricsStandardsFile string
	TracingStandardsFile string
	// TempoURL is the Grafana base URL used to build traceExploreUrl in
	// app_status responses. Set from IAF_TEMPO_URL. Empty = feature disabled.
	TempoURL string
	// SessionTTL is the idle TTL for new sessions. 0 = sessions never expire.
	SessionTTL time.Duration
}

// ResolveNamespace looks up the session and returns its namespace.
// It also updates the session's LastActivityAt to extend the TTL.
func (d *Dependencies) ResolveNamespace(sessionID string) (string, error) {
	sess, ok := d.Sessions.Lookup(sessionID)
	if !ok {
		return "", fmt.Errorf("session not found, call the register tool first")
	}
	d.Sessions.Touch(sessionID)
	return sess.Namespace, nil
}

// CheckAppNameAvailable verifies that no application with the given name exists
// in any other namespace. This prevents hostname collisions since all apps
// share the same base domain regardless of namespace.
func (d *Dependencies) CheckAppNameAvailable(ctx context.Context, appName, currentNamespace string) error {
	var allApps iafv1alpha1.ApplicationList
	if err := d.Client.List(ctx, &allApps); err != nil {
		return fmt.Errorf("checking application name availability: %w", err)
	}
	for _, app := range allApps.Items {
		if app.Name == appName && app.Namespace != currentNamespace {
			return fmt.Errorf("application name %q is already in use in namespace %q — choose a different name", appName, app.Namespace)
		}
	}
	return nil
}

package main

import (
	"context"
	"fmt"
	"log/slog"
	"net/http"
	"os"
	"path/filepath"

	"github.com/dlapiduz/iaf/internal/api"
	"github.com/dlapiduz/iaf/internal/auth"
	"github.com/dlapiduz/iaf/internal/config"
	iafgithub "github.com/dlapiduz/iaf/internal/github"
	"github.com/dlapiduz/iaf/internal/k8s"
	iafmcp "github.com/dlapiduz/iaf/internal/mcp"
	"github.com/dlapiduz/iaf/internal/orgstandards"
	"github.com/dlapiduz/iaf/internal/sessiongc"
	"github.com/dlapiduz/iaf/internal/sourcestore"
	"github.com/labstack/echo/v4"
	gomcp "github.com/modelcontextprotocol/go-sdk/mcp"
	"k8s.io/client-go/kubernetes"
)

func main() {
	logger := slog.New(slog.NewJSONHandler(os.Stdout, nil))
	slog.SetDefault(logger)

	cfg, err := config.Load()
	if err != nil {
		logger.Error("failed to load config", "error", err)
		os.Exit(1)
	}

	// Create K8s clients
	k8sClient, err := k8s.NewClient(cfg.KubeConfig)
	if err != nil {
		logger.Error("failed to create kubernetes client", "error", err)
		os.Exit(1)
	}

	restConfig, err := k8s.GetConfig(cfg.KubeConfig)
	if err != nil {
		logger.Error("failed to get kubernetes config", "error", err)
		os.Exit(1)
	}
	clientset, err := kubernetes.NewForConfig(restConfig)
	if err != nil {
		logger.Error("failed to create kubernetes clientset", "error", err)
		os.Exit(1)
	}

	// Create source store
	store, err := sourcestore.New(cfg.SourceStoreDir, cfg.SourceStoreURL, logger)
	if err != nil {
		logger.Error("failed to create source store", "error", err)
		os.Exit(1)
	}

	// Create session store

	// Create session store
	sessionsPath := filepath.Join(cfg.SourceStoreDir, "sessions.json")
	sessions, err := auth.NewSessionStore(sessionsPath)
	if err != nil {
		logger.Error("failed to create session store", "error", err)
		os.Exit(1)
	}

	// Create and configure Echo server
	e := api.NewServer(cfg.APITokens, logger)

	// Register REST API routes
	api.RegisterRoutes(e, k8sClient, clientset, sessions, store)

	// Mount source store file server
	e.GET("/sources/*", echo.WrapHandler(http.StripPrefix("/sources/", store.Handler())))

	// Create org standards loader (hot-reloads from IAF_ORG_STANDARDS_FILE)
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()
	orgLoader := orgstandards.New(cfg.OrgStandardsFile, logger)
	go orgLoader.Start(ctx)

	// Start session GC if TTL and GC interval are configured.
	if cfg.SessionTTL > 0 && cfg.SessionGCInterval > 0 {
		cleaner := sessiongc.New(k8sClient, store, sessions, logger)
		go cleaner.Start(ctx, cfg.SessionGCInterval)
		logger.Info("session GC started", "ttl", cfg.SessionTTL, "interval", cfg.SessionGCInterval)
	}

	// Create GitHub client if configured.
	var ghClient iafgithub.Client
	if cfg.GitHubToken != "" && cfg.GitHubOrg != "" {
		ghClient = iafgithub.NewHTTPClient(cfg.GitHubToken)
	}

	// Create MCP server and mount as Streamable HTTP endpoint
	mcpServer := iafmcp.NewServer(k8sClient, sessions, store, cfg.BaseDomain, orgLoader, ghClient, cfg.GitHubOrg, cfg.GitHubToken, cfg.TempoURL, cfg.SessionTTL, clientset)

	// If a coach URL is configured, enumerate coach prompts/resources and register
	// forwarding closures on the platform server so agents see them transparently.
	// Graceful degradation: unreachable coach is a warning, not a fatal startup error.
	if cfg.CoachURL != "" {
		if err := iafmcp.RegisterCoachProxy(ctx, mcpServer, cfg.CoachURL, cfg.CoachToken); err != nil {
			logger.Warn("coach proxy registration failed", "error", err)
		}
	}

	mcpHandler := gomcp.NewStreamableHTTPHandler(func(r *http.Request) *gomcp.Server {
		return mcpServer
	}, &gomcp.StreamableHTTPOptions{Stateless: true})
	e.Any("/mcp", echo.WrapHandler(mcpHandler))

	addr := fmt.Sprintf(":%d", cfg.APIPort)
	logger.Info("starting API server", "addr", addr, "mcp", fmt.Sprintf("http://localhost%s/mcp", addr))
	if err := e.Start(addr); err != nil {
		logger.Error("API server exited with error", "error", err)
		os.Exit(1)
	}
}

