		cs := k8sfake.NewSimpleClientset()
		server = iafmcp.NewServer(k8sClient, sessions, store, "test.example.com", nil, nil, "", "", "", 0, cs)
	} else {
		server = iafmcp.NewServer(k8sClient, sessions, store, "test.example.com", nil, nil, "", "", "", 0)
