package coach

import "github.com/dlapiduz/iaf/internal/orgstandards"

// Dependencies holds shared dependencies for the coach MCP server.
// Unlike the platform Dependencies, this struct has no K8s client and no session store —
// the coach is stateless and read-only.
type Dependencies struct {
	BaseDomain           string
	OrgStandards         *orgstandards.Loader
	LoggingStandardsFile string
	MetricsStandardsFile string
	TracingStandardsFile string
}

package coach

import (
	"fmt"
	"io"
	"os"
	"path/filepath"
	"strings"
)

const maxStandardsFileSize = 1 << 20 // 1 MB

// loadStandards returns the contents of the standards file at path, or the
// embedded default if path is empty. Returns an error only on I/O failures.
func loadStandards(path string, embedded []byte) ([]byte, error) {
	if path == "" {
		return embedded, nil
	}

	clean := filepath.Clean(path)
	if strings.Contains(clean, "..") {
		return nil, fmt.Errorf("standards file path must not contain traversal sequences")
	}

	f, err := os.Open(clean)
	if err != nil {
		if os.IsNotExist(err) {
			return embedded, nil
		}
		return nil, fmt.Errorf("opening standards file %q: %w", clean, err)
	}
	defer f.Close()

	data, err := io.ReadAll(io.LimitReader(f, maxStandardsFileSize))
	if err != nil {
		return nil, fmt.Errorf("reading standards file %q: %w", clean, err)
	}
	return data, nil
}

package coach

import (
	"context"
	_ "embed"
	"fmt"

	gomcp "github.com/modelcontextprotocol/go-sdk/mcp"
)

//go:embed defaults/logging-standards.json
var defaultLoggingStandards []byte

// RegisterLoggingStandards registers the iaf://org/logging-standards resource
// that exposes the platform's structured logging standard as JSON.
func RegisterLoggingStandards(server *gomcp.Server, deps *Dependencies) {
	server.AddResource(&gomcp.Resource{
		URI:         "iaf://org/logging-standards",
		Name:        "org-logging-standards",
		Description: "Platform logging standard — stdout-only, JSON Lines format, required fields (time/level/msg), prohibited content (secrets, PII), and trace correlation fields.",
		MIMEType:    "application/json",
	}, func(ctx context.Context, req *gomcp.ReadResourceRequest) (*gomcp.ReadResourceResult, error) {
		content, err := loadStandards(deps.LoggingStandardsFile, defaultLoggingStandards)
		if err != nil {
			return nil, fmt.Errorf("loading logging standards: %w", err)
		}
		return &gomcp.ReadResourceResult{
			Contents: []*gomcp.ResourceContents{
				{URI: req.Params.URI, MIMEType: "application/json", Text: string(content)},
			},
		}, nil
	})
}

package resources

import (
	"context"
	"encoding/json"
	"fmt"

	"github.com/dlapiduz/iaf/internal/mcp/tools"
	gomcp "github.com/modelcontextprotocol/go-sdk/mcp"
)

// RegisterGitHubStandards registers the iaf://org/github-standards resource
// that exposes org GitHub workflow conventions as structured JSON.
// Call only when GitHub is configured (deps.GitHub != nil).
func RegisterGitHubStandards(server *gomcp.Server, deps *tools.Dependencies) {
	server.AddResource(&gomcp.Resource{
		URI:         "iaf://org/github-standards",
		Name:        "github-standards",
		Description: "Organisation GitHub workflow conventions — branching strategy, branch protection, required status checks, commit format, and CI template.",
		MIMEType:    "application/json",
	}, func(ctx context.Context, req *gomcp.ReadResourceRequest) (*gomcp.ReadResourceResult, error) {
		standards := map[string]any{
			"defaultBranch":        "main",
			"branchNamingPattern":  "^(feat|fix|chore|docs|test)/[a-z0-9][a-z0-9-]*$",
			"requiredReviewers": map[string]int{
				"solo-agent":   0,
				"multi-agent":  1,
				"human-review": 1,
			},
			"requiredStatusChecks": []string{"CI / ci"},
			"commitMessageFormat":  "Conventional Commits (https://www.conventionalcommits.org)",
			"ciTemplate":           ".github/workflows/ci.yml",
			"iafIntegration": map[string]string{
				"deployBranch": "main",
				"deployMethod": "git",
			},
		}

		data, err := json.MarshalIndent(standards, "", "  ")
		if err != nil {
			return nil, fmt.Errorf("marshaling github standards: %w", err)
		}
		return &gomcp.ReadResourceResult{
			Contents: []*gomcp.ResourceContents{
				{URI: req.Params.URI, MIMEType: "application/json", Text: string(data)},
			},
		}, nil
	})
}

